// Helper functions
export const getUKCityById = (id) => ukCitiesFull.find(c => c.id === id);
export const getUKCitiesByOrgType = (orgType) => ukCitiesFull.filter(c => c.orgType === orgType);
export const getUKCitiesWithTargets = () => ukCitiesFull.filter(c => c.targets.length > 0);
export const getUKCitiesWithHazards = (hazardType) => ukCitiesFull.filter(c => 
  c.hazards.some(h => h.hazard?.toLowerCase().includes(hazardType.toLowerCase()))
);

// Statistics
export const ukCityStats = {
  totalCities: ukCitiesFull.length,
  totalHazards: ukCitiesFull.reduce((sum, c) => sum + c.hazards.length, 0),
  totalTargets: ukCitiesFull.reduce((sum, c) => sum + c.targets.length, 0),
  totalActions: ukCitiesFull.reduce((sum, c) => sum + c.actions.length, 0),
  citiesWithEmissions: ukCitiesFull.filter(c => c.emissions?.scopes?.length > 0).length
};

// Hazard types present
export const hazardTypes = [...new Set(ukCitiesFull.flatMap(c => c.hazards.map(h => h.hazard)).filter(Boolean))];
